    25→const MONTH_ABBR = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    26→
    27→// Weather mock data — would integrate with OpenWeatherMap API in production
    28→const SITE_WEATHER = {
    29→  temp: 14,
    30→  condition: 'Partly Cloudy',
    31→  wind: 12,
    32→  humidity: 68,
    33→  forecast: 'Clear conditions for next 48h',
