    36→// Build monthly chart data from invoices
    37→function buildChartData(invoices: AnyRow[]) {
    38→  const now = new Date();
    39→  const months: { month: string; revenue: number; profit: number }[] = [];
    40→  for (let i = 5; i >= 0; i--) {
    41→    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    42→    months.push({ month: MONTH_ABBR[d.getMonth()], revenue: 0, profit: 0 });
    43→  }
    44→  invoices.filter(inv => inv.status === 'paid').forEach(inv => {
    45→    const dateStr = String(inv.issueDate ?? inv.issue_date ?? '');
    46→    if (!dateStr) return;
    47→    const d = new Date(dateStr);
    48→    const mIdx = months.findIndex(m => m.month === MONTH_ABBR[d.getMonth()] && d.getFullYear() === new Date().getFullYear());
    49→    if (mIdx !== -1) {
    50→      months[mIdx].revenue += Number(inv.amount ?? 0);
    51→      months[mIdx].profit  += Number(inv.amount ?? 0) * 0.23;
    52→    }
    53→  });
    54→  return months;
    55→}
    56→
    57→// Project health dimensions for radar chart
    58→function buildHealthData(projects: AnyRow[], safety: AnyRow[], invoices: AnyRow[]) {
    59→  const active = projects.filter(p => p.status === 'active');
    60→  const avgProgress = active.length ? active.reduce((s, p) => s + Number(p.progress ?? 0), 0) / active.length : 0;
    61→  const budgetHealth = active.length ? active.reduce((s, p) => {
    62→    const burn = Number(p.spent ?? 0) / (Number(p.budget ?? 1) || 1);
    63→    return s + (1 - Math.abs(burn - Number(p.progress ?? 0) / 100));
    64→  }, 0) / active.length * 100 : 50;
    65→  const safetyScore = Math.max(0, 100 - safety.filter(s => ['open', 'investigating'].includes(String(s.status))).length * 15);
    66→  const rfiTurnaround = 70 - projects.length; // Simplified - would use actual RFI data
    67→  const cashHealth = invoices.length ? invoices.filter(i => i.status === 'paid').length / invoices.length * 100 : 50;
    68→  const compliance = 85; // Would be computed from RAMS expiry, training certs, etc.
    69→
    70→  return [
    71→    { dimension: 'Progress', score: Math.round(avgProgress), fullMark: 100 },
    72→    { dimension: 'Budget', score: Math.round(budgetHealth), fullMark: 100 },
    73→    { dimension: 'Safety', score: safetyScore, fullMark: 100 },
    74→    { dimension: 'RFIs', score: Math.max(0, rfiTurnaround), fullMark: 100 },
    75→    { dimension: 'Cash Flow', score: Math.round(cashHealth), fullMark: 100 },
    76→    { dimension: 'Compliance', score: compliance, fullMark: 100 },
    77→  ];
    78→}
    79→
    80→function fmtM(n: number) {
    81→  if (n >= 1_000_000) return `£${(n / 1_000_000).toFixed(2)}M`;
    82→  if (n >= 1_000)     return `£${(n / 1_000).toFixed(0)}K`;
    83→  return `£${n.toLocaleString()}`;
    84→}
