    86→// Enhanced Stat Card with sparkline trend
    87→function StatCard({
    88→  label, value, sub, positive, icon: Icon, delay, onClick, trendData, secondaryValue,
    89→}: {
    90→  label: string; value: string; sub: string; positive: boolean;
    91→  icon: React.FC<{ className?: string; style?: React.CSSProperties }>;
    92→  delay: number; onClick?: () => void; trendData?: number[]; secondaryValue?: string;
    93→}) {
    94→  return (
    95→    <button
    96→      onClick={onClick}
    97→      className="card card-grid card-hover animate-fade-up"
    98→      style={{ animationDelay: `${delay}ms`, padding: '0', cursor: onClick ? 'pointer' : 'default', textAlign: 'left', width: '100%', border: 'none', overflow: 'hidden' }}
    99→    >
   100→      {/* Amber top accent line */}
   101→      <div style={{
   102→        position: 'absolute', top: 0, left: '0', right: '0', height: '3px',
   103→        background: positive
   104→          ? 'linear-gradient(90deg, var(--amber-500), var(--amber-400), var(--emerald-400))'
   105→          : 'linear-gradient(90deg, var(--slate-700), var(--red-400))',
   106→      }} />
   107→
   108→      <div style={{ padding: '18px', position: 'relative', zIndex: 1 }}>
   109→        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
   110→          <span className="text-label-xs" style={{ color: 'var(--slate-400)' }}>{label}</span>
   111→          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
   112→            {trendData && (
   113→              <div style={{ width: '40px', height: '24px', opacity: 0.6 }}>
   114→                <ResponsiveContainer width="100%" height="100%">
   115→                  <AreaChart data={trendData.map((v, i) => ({ i, v }))}>
   116→                    <Area type="monotone" dataKey="v" stroke={positive ? 'var(--emerald-400)' : 'var(--red-400)'} fill="none" strokeWidth={1.5} />
   117→                  </AreaChart>
   118→                </ResponsiveContainer>
   119→              </div>
   120→            )}
   121→            <Icon style={{ width: '18px', height: '18px', color: positive ? 'var(--amber-400)' : 'var(--slate-500)' }} />
   122→          </div>
   123→        </div>
   124→
   125→        <div style={{ display: 'flex', alignItems: 'baseline', gap: '12px', marginBottom: '10px' }}>
   126→          <div style={{ fontFamily: 'var(--font-mono)', fontSize: '1.5rem', fontWeight: 700, color: 'var(--slate-50)', letterSpacing: '-0.04em', lineHeight: 1 }}>
   127→            {value}
   128→          </div>
   129→          {secondaryValue && (
   130→            <div style={{ fontFamily: 'var(--font-mono)', fontSize: '0.75rem', fontWeight: 600, color: 'var(--slate-400)', whiteSpace: 'nowrap' }}>
   131→              {secondaryValue}
   132→            </div>
   133→          )}
   134→        </div>
   135→
   136→        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
   137→          {positive
   138→            ? <TrendingUp style={{ width: '12px', height: '12px', color: 'var(--emerald-400)' }} />
   139→            : <TrendingDown style={{ width: '12px', height: '12px', color: 'var(--red-400)' }} />
   140→          }
   141→          <span style={{
   142→            fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 500,
   143→            color: positive ? 'var(--emerald-400)' : 'var(--red-400)',
   144→            letterSpacing: '0.04em',
   145→          }}>
   146→            {sub}
   147→          </span>
   148→        </div>
   149→      </div>
   150→    </button>
   151→  );
   152→}
