   184→
   185→// Critical Alert Carousel
   186→function AlertCarousel({ alerts }: { alerts: { id: string; title: string; severity: 'critical' | 'warning' | 'info'; module: Module; time: string }[] }) {
   187→  const [idx, setIdx] = useState(0);
   188→  const severityCfg = {
   189→    critical: { bg: 'rgba(248,113,113,0.1)', border: 'rgba(248,113,113,0.3)', color: 'var(--red-400)' },
   190→    warning: { bg: 'rgba(245,158,11,0.1)', border: 'rgba(245,158,11,0.3)', color: 'var(--amber-400)' },
   191→    info: { bg: 'rgba(59,130,246,0.1)', border: 'rgba(59,130,246,0.3)', color: 'var(--blue-400)' },
   192→  };
   193→  const current = alerts[idx];
   194→  const cfg = severityCfg[current.severity];
   195→
   196→  return (
   197→    <div className="card animate-fade-up delay-2" style={{ padding: '0', overflow: 'hidden', border: `1px solid ${cfg.border}`, background: cfg.bg }}>
   198→      <div style={{ padding: '14px 18px', display: 'flex', alignItems: 'center', gap: '12px' }}>
   199→        <AlertCircle style={{ width: '18px', height: '18px', color: cfg.color, flexShrink: 0 }} />
   200→        <div style={{ flex: 1, overflow: 'hidden' }}>
   201→          <div style={{ fontFamily: 'var(--font-body)', fontSize: '12px', fontWeight: 600, color: 'var(--slate-100)', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
   202→            {current.title}
   203→          </div>
   204→          <div style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)', marginTop: '2px' }}>
   205→            {current.time}
   206→          </div>
   207→        </div>
   208→        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
   209→          <button onClick={() => setIdx((idx - 1 + alerts.length) % alerts.length)} style={{ background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '6px', padding: '4px', cursor: 'pointer', color: 'var(--slate-400)' }}>
   210→            <ChevronRight style={{ width: '14px', height: '14px', transform: 'rotate(180deg)' }} />
   211→          </button>
   212→          <button onClick={() => setIdx((idx + 1) % alerts.length)} style={{ background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '6px', padding: '4px', cursor: 'pointer', color: 'var(--slate-400)' }}>
   213→            <ChevronRight style={{ width: '14px', height: '14px' }} />
   214→          </button>
   215→        </div>
   216→      </div>
   217→      <div style={{ display: 'flex', gap: '3px', padding: '0 18px', paddingBottom: '12px' }}>
   218→        {alerts.map((_, i) => (
   219→          <div key={i} style={{ flex: 1, height: '2px', borderRadius: '1px', background: i === idx ? cfg.color : 'var(--slate-800)' }} />
   220→        ))}
   221→      </div>
   222→    </div>
   223→  );
   224→}
   225→
   226→// Resource Heatmap
   227→function ResourceHeatmap({ projects }: { projects: AnyRow[] }) {
   228→  const trades = [
   229→    { name: 'Groundworks', workers: Math.round(projects.reduce((s, p) => s + (Number(p.workers ?? 0) * 0.15), 0)), color: 'var(--emerald-500)' },
   230→    { name: 'Structural', workers: Math.round(projects.reduce((s, p) => s + (Number(p.workers ?? 0) * 0.25), 0)), color: 'var(--amber-500)' },
   231→    { name: 'MEP', workers: Math.round(projects.reduce((s, p) => s + (Number(p.workers ?? 0) * 0.2), 0)), color: 'var(--blue-500)' },
   232→    { name: 'Finishing', workers: Math.round(projects.reduce((s, p) => s + (Number(p.workers ?? 0) * 0.2), 0)), color: 'var(--purple-500)' },
   233→    { name: 'External', workers: Math.round(projects.reduce((s, p) => s + (Number(p.workers ?? 0) * 0.1), 0)), color: 'var(--orange-500)' },
   234→    { name: 'Management', workers: Math.round(projects.reduce((s, p) => s + (Number(p.workers ?? 0) * 0.1), 0)), color: 'var(--slate-500)' },
   235→  ];
   236→  const maxWorkers = Math.max(...trades.map(t => t.workers));
   237→
   238→  return (
   239→    <div className="card card-grid" style={{ padding: '20px', gridColumn: 'span 2' }}>
   240→      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
   241→        <div>
   242→          <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-100)', letterSpacing: '-0.01em' }}>Resource Distribution</h3>
   243→          <p style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)', letterSpacing: '0.08em', textTransform: 'uppercase', marginTop: '2px' }}>Workforce by trade</p>
   244→        </div>
   245→      </div>
   246→      <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
   247→        {trades.map(trade => (
   248→          <div key={trade.name} style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
   249→            <div style={{ width: '80px', fontFamily: 'var(--font-mono)', fontSize: '10px', color: 'var(--slate-400)', textAlign: 'right' }}>{trade.name}</div>
   250→            <div style={{ flex: 1, height: '20px', background: 'var(--slate-800)', borderRadius: '4px', overflow: 'hidden', position: 'relative' }}>
   251→              <div style={{ height: '100%', width: `${(trade.workers / maxWorkers) * 100}%`, background: `linear-gradient(90deg, ${trade.color}88, ${trade.color})`, borderRadius: '4px', display: 'flex', alignItems: 'center', justifyContent: 'flex-end', paddingRight: '8px' }}>
   252→                <span style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 700, color: 'white', textShadow: '0 1px 2px rgba(0,0,0,0.5)' }}>{trade.workers}</span>
   253→              </div>
   254→            </div>
   255→            <div style={{ width: '60px', fontFamily: 'var(--font-mono)', fontSize: '11px', fontWeight: 600, color: 'var(--slate-300)', textAlign: 'right' }}>{trade.workers}</div>
   256→          </div>
   257→        ))}
   258→      </div>
   259→    </div>
   260→  );
   261→}
   262→
   263→export function Dashboard({ setModule }: DashboardProps) {
   264→  const { data: rawProjects  = [] } = useProjects.useList();
   265→  const { data: rawInvoices  = [] } = useInvoices.useList();
   266→  const { data: rawTeam      = [] } = useTeam.useList();
   267→  const { data: rawSafety    = [] } = useSafety.useList();
   268→  const { data: rawRFIs      = [] } = useRFIs.useList();
   269→  const { data: rawReports   = [] } = useDailyReports.useList();
   270→
   271→  const projects  = rawProjects  as AnyRow[];
   272→  const invoices  = rawInvoices  as AnyRow[];
   273→  const team      = rawTeam      as AnyRow[];
   274→  const safety    = rawSafety    as AnyRow[];
   275→  const rfis      = rawRFIs      as AnyRow[];
   276→  const reports   = rawReports   as AnyRow[];
   277→
   278→  const healthData = useMemo(() => buildHealthData(projects, safety, invoices), [projects, safety, invoices]);
   279→  const chartData  = buildChartData(invoices);
   280→  const activeProjects = projects.filter(p => p.status === 'active').slice(0, 3);
   281→  const totalRevenue   = invoices.filter(i => i.status === 'paid').reduce((s, i) => s + Number(i.amount ?? 0), 0);
   282→  const outstanding    = invoices.filter(i => i.status === 'sent' || i.status === 'overdue').reduce((s, i) => s + Number(i.amount ?? 0), 0);
   283→  const workerCount    = team.filter(m => m.status === 'active' || !m.status).length;
   284→  const openIncidents = safety.filter(s => s.status === 'open' || s.status === 'investigating').length;
   285→  const openRFIs      = rfis.filter(r => r.status === 'open' || r.status === 'pending').length;
   286→  const safetyDays    = safety.filter(s => s.type === 'incident' || s.type === 'riddor').length;
   287→  const overdueInvoices = invoices.filter(i => i.status === 'overdue').length;
   288→  const expiringRAMS = 2;
   289→
   290→  // Build critical alerts
   291→  const alerts: { id: string; title: string; severity: 'critical' | 'warning' | 'info'; module: Module; time: string }[] = [];
   292→  if (openIncidents > 0) alerts.push({ id: 'safety', title: `${openIncidents} open safety incident${openIncidents > 1 ? 's' : ''} requires attention`, severity: 'critical', module: 'safety', time: 'Now' });
   293→  if (overdueInvoices > 0) alerts.push({ id: 'finance', title: `${overdueInvoices} invoice${overdueInvoices > 1 ? 's' : ''} overdue for payment`, severity: 'critical', module: 'invoicing', time: 'Today' });
   294→  if (expiringRAMS > 0) alerts.push({ id: 'compliance', title: `${expiringRAMS} RAMS document${expiringRAMS > 1 ? 's' : ''} expiring within 30 days`, severity: 'warning', module: 'rams', time: 'This week' });
   295→  if (openRFIs > 0) alerts.push({ id: 'rfi', title: `${openRFIs} RFI${openRFIs > 1 ? 's' : ''} awaiting response`, severity: 'warning', module: 'rfis', time: 'Pending' });
   296→
   297→  // Activity feed
   298→  type ActivityEntry = { label: string; time: string; dotColor: string; module: Module };
   299→  const activityFeed: ActivityEntry[] = [];
   300→
   301→  invoices.slice(0, 3).forEach(inv => {
   302→    const status = String(inv.status ?? '');
   303→    activityFeed.push({
   304→      label: `Invoice ${inv.number ?? ''} ${status === 'paid' ? 'paid' : status === 'sent' ? 'sent to' : `(${status})`} ${inv.client ?? ''}`,
   305→      time: String(inv.issueDate ?? inv.issue_date ?? ''),
   306→      dotColor: status === 'paid' ? 'var(--emerald-400)' : status === 'overdue' ? 'var(--red-400)' : 'var(--amber-400)',
   307→      module: 'invoicing',
   308→    });
   309→  });
   310→
   311→  safety.filter(s => s.status === 'open' || s.status === 'investigating').slice(0, 2).forEach(inc => {
   312→    activityFeed.push({
   313→      label: `Safety: ${inc.title ?? ''} — ${inc.project ?? ''}`,
   314→      time: String(inc.date ?? ''),
   315→      dotColor: String(inc.severity ?? '') === 'critical' ? 'var(--red-400)' : 'var(--amber-400)',
   316→      module: 'safety',
   317→    });
   318→  });
   319→
   320→  reports.slice(0, 2).forEach(r => {
   321→    activityFeed.push({
   322→      label: `Daily report — ${r.project ?? ''}`,
   323→      time: String(r.date ?? ''),
   324→      dotColor: 'var(--emerald-400)',
   325→      module: 'daily-reports',
   326→    });
   327→  });
   328→
   329→  rfis.filter(r => r.status === 'open' || r.status === 'pending').slice(0, 2).forEach(rfi => {
   330→    activityFeed.push({
   331→      label: `${rfi.number ?? ''} — ${rfi.subject ?? ''}`,
   332→      time: String(rfi.submittedDate ?? rfi.submitted_date ?? ''),
   333→      dotColor: 'var(--slate-400)',
   334→      module: 'rfis',
   335→    });
   336→  });
   337→
   338→  const recentActivities = activityFeed
   339→    .sort((a, b) => (b.time > a.time ? 1 : b.time < a.time ? -1 : 0))
   340→    .slice(0, 7)
   341→    .map(a => {
   342→      const diff = Math.floor((Date.now() - new Date(a.time).getTime()) / 86400000);
   343→      const timeLabel = !a.time || a.time === 'undefined' ? '' : diff === 0 ? 'Today' : diff === 1 ? 'Yesterday' : `${diff}d ago`;
   344→      return { ...a, time: timeLabel };
   345→    });
   346→
   347→  // Overall health score
   348→  const overallHealth = Math.round(healthData.reduce((s, d) => s + d.score, 0) / healthData.length);
   349→  const healthColor = overallHealth >= 80 ? 'var(--emerald-400)' : overallHealth >= 60 ? 'var(--amber-400)' : 'var(--red-400)';
   350→  const healthTrend = 'up';
   351→
   352→  return (
   353→    <div
   354→      className="module-page"
   355→      style={{ minHeight: '100%', background: 'var(--slate-950)', padding: '24px' }}
   356→    >
   357→      {/* ── Command Center Header ─────────────────────────────────── */}
   358→      <div
   359→        className="card animate-fade-up delay-0"
   360→        style={{
