      </div>

      {/* ── Alert Carousel ────────────────────────────────────── */}
      {alerts.length > 0 && (
        <AlertCarousel alerts={alerts} />
      )}

      {/* ── KPI Grid ────────────────────────────────────── */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(6, 1fr)',
          gap: '12px', marginBottom: '20px',
        }}
      >
        <div className="animate-fade-up delay-1">
          <StatCard
