                  onMouseLeave={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.03)'; e.currentTarget.style.borderColor = 'var(--slate-800)'; }}
                >
                  <Icon style={{ width: '16px', height: '16px', color: 'var(--amber-400)' }} />
