   227→          const sev = severityConfig[String(inc.severity)] ?? severityConfig.low;
   228→          const stat = statusConfig[String(inc.status)] ?? statusConfig.open;
   229→          const typeInfo = typeConfig[String(inc.type)] ?? { label: String(inc.type), icon: Shield };
   230→          const TypeIcon = typeInfo.icon;
   231→          return (
   232→            <div key={String(inc.id)}
   233→              className={clsx(
   234→                'rounded-2xl border bg-gray-900 p-5 cursor-pointer transition-all hover:border-gray-700',
   235→                selectedId === String(inc.id) ? 'border-red-600/50 ring-1 ring-red-500/20' : 'border-gray-800'
   236→              )}
   237→              onClick={() => setSelectedId(prev => prev===String(inc.id)?null:String(inc.id))}>
   238→              <div className="flex items-start justify-between gap-3">
   239→                <div className="flex items-start gap-3 flex-1 min-w-0">
   240→                  <div className={clsx('p-2 rounded-xl shrink-0', sev.bg)}>
   241→                    <TypeIcon className={clsx('w-4 h-4', sev.color)} />
   242→                  </div>
   243→                  <div className="flex-1 min-w-0">
   244→                    <div className="flex items-center gap-2 flex-wrap">
   245→                      <h3 className="font-semibold text-white text-sm">{String(inc.title)}</h3>
   246→                      {(inc.riddor_reportable || inc.type === 'riddor') && (
   247→                        <span className="rounded-full bg-purple-500/20 border border-purple-600/40 px-2 py-0.5 text-xs font-bold text-purple-400">RIDDOR</span>
   248→                      )}
   249→                    </div>
   250→                    <div className="flex flex-wrap gap-x-4 gap-y-1 mt-1 text-xs text-gray-400">
   251→                      <span>{typeInfo.label}</span>
   252→                      {!!inc.project && <span>{String(inc.project)}</span>}
   253→                      {!!inc.date && <span>{String(inc.date)}</span>}
   254→                      {(inc.reported_by_name || inc.reportedBy) ? <span>By: {String(inc.reported_by_name ?? inc.reportedBy)}</span> : null}
   255→                    </div>
   256→                    {selectedId === String(inc.id) && !!inc.description && (
   257→                      <p className="mt-2 text-xs text-gray-400 leading-relaxed">{String(inc.description)}</p>
   258→                    )}
   259→                  </div>
   260→                </div>
   261→                <div className="flex flex-col items-end gap-2 shrink-0">
   262→                  <span className={clsx('rounded-full px-2.5 py-1 text-xs font-bold', sev.bg, sev.color)}>{sev.label}</span>
   263→                  <span className={clsx('text-xs font-semibold', stat.color)}>{stat.label}</span>
   264→                </div>
   265→              </div>
   266→              {selectedId === String(inc.id) && (
   267→                <div className="flex gap-2 mt-4 pt-4 border-t border-gray-800" onClick={e => e.stopPropagation()}>
   268→                  <button onClick={() => openEdit(inc)}
   269→                    className="flex-1 flex items-center justify-center gap-1.5 rounded-xl bg-gray-800 hover:bg-gray-700 py-2 text-xs font-semibold text-white transition-colors">
   270→                    <Edit2 className="w-3.5 h-3.5" /> Edit Record
   271→                  </button>
   272→                  {String(inc.status) !== 'closed' && (
   273→                    <button onClick={() => updateM.mutateAsync({ id: String(inc.id), data: { status: 'closed' } })}
   274→                      className="flex-1 flex items-center justify-center gap-1.5 rounded-xl bg-green-600/20 hover:bg-green-600/30 border border-green-600/30 py-2 text-xs font-semibold text-green-400 transition-colors">
   275→                      <CheckCircle2 className="w-3.5 h-3.5" /> Close Incident
   276→                    </button>
   277→                  )}
   278→                  <button onClick={() => handleDelete(String(inc.id))}
   279→                    className="rounded-xl bg-gray-800 hover:bg-red-900/20 px-3 py-2 text-red-500 hover:text-red-400 transition-colors">
   280→                    <Trash2 className="w-3.5 h-3.5" />
   281→                  </button>
   282→                </div>
   283→              )}
   284→            </div>
   285→          );
   286→        })}
   287→        {!isLoading && filtered.length === 0 && (
   288→          <div className="text-center py-16 text-gray-500">
   289→            <Shield className="w-12 h-12 mx-auto mb-3 text-gray-700" />
   290→            <p className="font-medium">No incidents recorded</p>
   291→            <button onClick={openCreate} className="mt-3 text-sm text-red-400 hover:text-red-300">+ Report an incident</button>
   292→          </div>
   293→        )}
   294→      </div>
   295→
   296→      {/* Modal */}
   297→      {showModal && (
   298→        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4 overflow-y-auto backdrop-blur-sm">
   299→          <div className="w-full max-w-2xl rounded-2xl border border-gray-700 bg-gray-900 shadow-2xl my-4">
   300→            <div className="flex items-center justify-between px-6 pt-6 pb-4 border-b border-gray-800">
   301→              <div>
   302→                <h2 className="text-xl font-bold text-white">{editId ? 'Edit Incident' : 'Report Incident'}</h2>
   303→                <p className="text-xs text-gray-400 mt-0.5">Record a safety incident, near miss or hazard</p>
   304→              </div>
   305→              <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-white p-2 rounded-xl hover:bg-gray-800"><X className="w-5 h-5" /></button>
   306→            </div>
   307→            <form onSubmit={handleSubmit} className="p-6 grid grid-cols-2 gap-4">
   308→              <div className="col-span-2">
   309→                <label className={lbl}>Title *</label>
   310→                <input required value={form.title} onChange={e => setForm(p=>({...p,title:e.target.value}))} placeholder="Brief description of the incident" className={inp} />
   311→              </div>
   312→              <div>
   313→                <label className={lbl}>Type</label>
   314→                <select value={form.type} onChange={e => setForm(p=>({...p,type:e.target.value}))} className={inp}>
   315→                  {Object.entries(typeConfig).slice(0,5).map(([k,v]) => <option key={k} value={k}>{v.label}</option>)}
   316→                </select>
   317→              </div>
   318→              <div>
   319→                <label className={lbl}>Severity</label>
   320→                <select value={form.severity} onChange={e => setForm(p=>({...p,severity:e.target.value}))} className={inp}>
   321→                  {['low','medium','high','critical'].map(s => <option key={s} value={s} className="capitalize">{s.charAt(0).toUpperCase()+s.slice(1)}</option>)}
   322→                </select>
   323→              </div>
   324→              <div>
   325→                <label className={lbl}>Status</label>
   326→                <select value={form.status} onChange={e => setForm(p=>({...p,status:e.target.value}))} className={inp}>
   327→                  {Object.keys(statusConfig).map(s => <option key={s} value={s}>{statusConfig[s].label}</option>)}
   328→                </select>
   329→              </div>
   330→              <div>
   331→                <label className={lbl}>Date</label>
   332→                <input type="date" value={form.date} onChange={e => setForm(p=>({...p,date:e.target.value}))} className={inp} />
   333→              </div>
   334→              <div>
   335→                <label className={lbl}>Project</label>
   336→                <input value={form.project} onChange={e => setForm(p=>({...p,project:e.target.value}))} placeholder="Project name" className={inp} />
   337→              </div>
   338→              <div>
   339→                <label className={lbl}>Location on Site</label>
   340→                <input value={form.location} onChange={e => setForm(p=>({...p,location:e.target.value}))} placeholder="e.g. Level 7, Grid C4" className={inp} />
   341→              </div>
   342→              <div>
   343→                <label className={lbl}>Reported By</label>
   344→                <input value={form.reported_by_name} onChange={e => setForm(p=>({...p,reported_by_name:e.target.value}))} placeholder="Name" className={inp} />
   345→              </div>
   346→              <div>
   347→                <label className={lbl}>Injured Party (if any)</label>
   348→                <input value={form.injured_party} onChange={e => setForm(p=>({...p,injured_party:e.target.value}))} placeholder="Name / N/A" className={inp} />
   349→              </div>
   350→              <div className="col-span-2">
   351→                <label className={lbl}>Description</label>
   352→                <textarea rows={3} value={form.description} onChange={e => setForm(p=>({...p,description:e.target.value}))}
   353→                  placeholder="What happened? Include sequence of events..."
   354→                  className="w-full bg-gray-800 border border-gray-700 rounded-xl px-4 py-2.5 text-white text-sm placeholder-gray-600 focus:outline-none focus:border-red-500 transition-colors resize-none" />
   355→              </div>
   356→              <div className="col-span-2">
   357→                <label className={lbl}>Immediate Action Taken</label>
   358→                <textarea rows={2} value={form.immediate_action} onChange={e => setForm(p=>({...p,immediate_action:e.target.value}))}
   359→                  placeholder="Steps taken immediately after the incident..."
   360→                  className="w-full bg-gray-800 border border-gray-700 rounded-xl px-4 py-2.5 text-white text-sm placeholder-gray-600 focus:outline-none focus:border-red-500 transition-colors resize-none" />
   361→              </div>
   362→              <div className="col-span-2 flex items-center gap-3 p-3 rounded-xl bg-purple-500/10 border border-purple-600/30">
   363→                <input type="checkbox" id="riddor" checked={form.riddor_reportable}
   364→                  onChange={e => setForm(p=>({...p,riddor_reportable:e.target.checked}))}
   365→                  className="w-4 h-4 rounded border-gray-600 bg-gray-800 text-purple-500 focus:ring-purple-500" />
   366→                <label htmlFor="riddor" className="text-sm text-purple-300 cursor-pointer">
   367→                  <span className="font-bold">RIDDOR reportable</span> — must be reported to HSE within 10 days
   368→                </label>
   369→              </div>
   370→              <div className="col-span-2 flex gap-3 pt-2">
   371→                <button type="button" onClick={() => setShowModal(false)}
   372→                  className="flex-1 rounded-xl bg-gray-800 hover:bg-gray-700 py-3 text-sm font-semibold text-gray-300 transition-colors">Cancel</button>
   373→                <button type="submit" disabled={createM.isPending||updateM.isPending}
   374→                  className="flex-[2] rounded-xl bg-gradient-to-r from-red-600 to-rose-600 hover:from-red-500 py-3 text-sm font-bold text-white transition-all shadow-lg shadow-red-500/20 disabled:opacity-50 flex items-center justify-center gap-2">
   375→                  {(createM.isPending||updateM.isPending) && <Loader2 className="w-4 h-4 animate-spin" />}
   376→                  {editId ? 'Save Changes' : 'Submit Report'}
   377→                </button>
   378→              </div>
   379→            </form>
   380→          </div>
   381→        </div>
   382→      )}
   383→    </div>
   384→  );
   385→}
