// Module: Safety — CortexBuild Ultimate
// "HSE Intelligence Hub" Redesign — Industrial Intelligence Aesthetic
import { useState, useMemo } from 'react';
import {
  Shield, AlertTriangle, CheckCircle2, AlertCircle, FileText,
  Plus, X, Loader2, Search, Edit2, Trash2, RefreshCw, TrendingUp,
  TrendingDown, Activity, Clock, Users, MapPin, Calendar, Eye,
  BarChart3, PieChart, Target, Zap, Radar, Thermometer, HardHat,
  ChevronRight, Bell, Filter, Download, AlertCircle as AlertCircleIcon,
} from 'lucide-react';
import { useSafety, useProjects, useTeam } from '../../hooks/useData';
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  BarChart, Bar, LabelList, Pie, PieChart as RechartsPie, Cell,
  AreaChart, Area,
} from 'recharts';
import type { Module } from '../../types';

type AnyRow = Record<string, unknown>;

const severityConfig: Record<string, { label: string; color: string; bg: string; stroke: string }> = {
  low:      { label: 'Low',      color: 'var(--emerald-400)',  bg: 'rgba(16,185,129,0.1)',  stroke: 'rgba(16,185,129,0.3)' },
  medium:   { label: 'Medium',   color: 'var(--amber-400)',    bg: 'rgba(245,158,11,0.1)',   stroke: 'rgba(245,158,11,0.3)' },
  high:     { label: 'High',     color: 'var(--orange-400)',   bg: 'rgba(251,146,60,0.1)',   stroke: 'rgba(251,146,60,0.3)' },
  critical: { label: 'Critical', color: 'var(--red-400)',      bg: 'rgba(248,113,113,0.1)',  stroke: 'rgba(248,113,113,0.3)' },
  minor:    { label: 'Minor',    color: 'var(--emerald-400)',  bg: 'rgba(16,185,129,0.1)',   stroke: 'rgba(16,185,129,0.3)' },
  serious:  { label: 'Serious',  color: 'var(--orange-400)',   bg: 'rgba(251,146,60,0.1)',   stroke: 'rgba(251,146,60,0.3)' },
};

const statusConfig: Record<string, { label: string; color: string; bg: string }> = {
  open:              { label: 'Open',             color: 'var(--red-400)',      bg: 'rgba(248,113,113,0.1)' },
  investigating:     { label: 'Investigating',    color: 'var(--amber-400)',    bg: 'rgba(245,158,11,0.1)' },
  action_required:   { label: 'Action Required',  color: 'var(--orange-400)',   bg: 'rgba(251,146,60,0.1)' },
  closed:            { label: 'Closed',           color: 'var(--emerald-400)',  bg: 'rgba(16,185,129,0.1)' },
  resolved:          { label: 'Resolved',         color: 'var(--emerald-400)',  bg: 'rgba(16,185,129,0.1)' },
};

const typeConfig: Record<string, { label: string; icon: React.FC<{ className?: string }> }> = {
  near_miss:            { label: 'Near Miss',           icon: AlertTriangle },
  first_aid:            { label: 'First Aid',           icon: AlertCircle },
  riddor:               { label: 'RIDDOR',              icon: FileText },
  dangerous_occurrence: { label: 'Dangerous Occurrence',icon: AlertTriangle },
  environmental:        { label: 'Environmental',       icon: Shield },
  incident:             { label: 'Incident',            icon: AlertCircleIcon },
  hazard:               { label: 'Hazard',              icon: AlertTriangle },
  'toolbox-talk':       { label: 'Toolbox Talk',        icon: FileText },
  'mewp-check':         { label: 'MEWP Check',          icon: CheckCircle2 },
};

const COLORS = ['var(--red-400)', 'var(--orange-400)', 'var(--amber-400)', 'var(--emerald-400)'];

const defaultForm = {
  title: '', type: 'near_miss', severity: 'medium', status: 'open',
  project: '', location: '', date: new Date().toISOString().split('T')[0],
  description: '', immediate_action: '', injured_party: '',
  reported_by_name: '', riddor_reportable: false, root_cause: 'human_factor',
};
type FormData = typeof defaultForm;

// Build 7-month trend data from actual incidents
function buildTrendData(incidents: AnyRow[]) {
  const months = ['Sep','Oct','Nov','Dec','Jan','Feb','Mar'];
  const data = months.map(month => ({ month, incidents: 0, nearMisses: 0, toolboxTalks: 0 }));
  incidents.forEach(inc => {
    const dateStr = String(inc.date ?? '');
    if (!dateStr) return;
    const d = new Date(dateStr);
    const mIdx = data.findIndex(m => m.month === months[d.getMonth() % 12]);
    if (mIdx === -1) return;
    const type = String(inc.type ?? '');
    if (['incident','first_aid','riddor'].includes(type)) data[mIdx].incidents++;
    else if (['near-miss','near_miss'].includes(type)) data[mIdx].nearMisses++;
    else if (['toolbox-talk','toolbox_talk'].includes(type)) data[mIdx].toolboxTalks++;
  });
  return data;
}

// Risk heatmap data by project and severity
function buildRiskHeatmap(incidents: AnyRow[], projects: AnyRow[]) {
  const projectRisk: Record<string, { name: string; critical: number; high: number; medium: number; low: number; score: number }> = {};
  projects.forEach(p => {
    const name = String(p.name ?? 'Unknown');
    projectRisk[name] = { name, critical: 0, high: 0, medium: 0, low: 0, score: 0 };
  });
  incidents.forEach(inc => {
    const proj = String(inc.project ?? 'Unknown');
    const sev = String(inc.severity ?? 'low');
    if (!projectRisk[proj]) projectRisk[proj] = { name: proj, critical: 0, high: 0, medium: 0, low: 0, score: 0 };
    projectRisk[proj][sev] = (projectRisk[proj][sev as 'critical'|'high'|'medium'|'low'] ?? 0) + 1;
    projectRisk[proj].score += sev === 'critical' ? 4 : sev === 'high' ? 3 : sev === 'medium' ? 2 : 1;
  });
  return Object.values(projectRisk).sort((a, b) => b.score - a.score);
}

// Root cause distribution
function buildRootCauseData(incidents: AnyRow[]) {
  const causes: Record<string, number> = {};
  incidents.forEach(inc => {
    const cause = String(inc.root_cause ?? 'unknown');
    causes[cause] = (causes[cause] ?? 0) + 1;
  });
  return Object.entries(causes).map(([name, value]) => ({ name, value }));
}

// Predictive risk forecast (simple projection)
function buildRiskForecast(incidents: AnyRow[]) {
  const recent = incidents.slice(0, 14);
  const avgSeverity = recent.reduce((s, i) => s + (['critical','high','medium','low'].includes(String(i.severity ?? '')) ? {critical:4,high:3,medium:2,low:1}[String(i.severity ?? 'low')] ?? 1 : 1), 0) / recent.length;
  const trend = recent.length > 7 ? (recent.length - recent.slice(7).length) / 7 : 0;
  return [
    { week: 'Current', riskScore: Math.round(avgSeverity * 25 + recent.length * 2) },
    { week: '+1 Week', riskScore: Math.round((avgSeverity + trend * 0.2) * 25 + (recent.length + trend * 2) * 2) },
    { week: '+2 Weeks', riskScore: Math.round((avgSeverity + trend * 0.4) * 25 + (recent.length + trend * 4) * 2) },
    { week: '+4 Weeks', riskScore: Math.round((avgSeverity + trend * 0.8) * 25 + (recent.length + trend * 8) * 2) },
  ];
}

export function Safety({ setModule }: { setModule?: (m: Module) => void }) {
  const { useList, useCreate, useUpdate, useDelete } = useSafety;
  const { data: rawProjects = [] } = useProjects.useList();
  const { data: rawTeam = [] } = useTeam.useList();
  const { data: raw = [], isLoading, refetch } = useList();
  const incidents = raw as AnyRow[];
  const createM = useCreate(); const updateM = useUpdate(); const deleteM = useDelete();

  const [categoryTab, setCategoryTab] = useState('all');
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<FormData>(defaultForm);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const TYPE_MAP: Record<string, string[]> = {
    all:          [],
    incidents:    ['incident','first_aid','riddor'],
    near_misses:  ['near-miss','near_miss'],
    hazards:      ['hazard','dangerous_occurrence','environmental'],
    mewp:         ['mewp-check','mewp_check'],
    toolbox:      ['toolbox-talk','toolbox_talk'],
    riddor:       ['riddor'],
  };

  const filtered = incidents
    .filter(i => categoryTab === 'all' || TYPE_MAP[categoryTab]?.includes(String(i.type ?? '')))
    .filter(i => filter === 'all' || i.status === filter || i.severity === filter)
    .filter(i => !search || String(i.title).toLowerCase().includes(search.toLowerCase()) || String(i.project).toLowerCase().includes(search.toLowerCase()));

  const counts = {
    open: incidents.filter(i => ['open','investigating','action_required'].includes(String(i.status ?? ''))).length,
    critical: incidents.filter(i => ['critical','serious'].includes(String(i.severity ?? ''))).length,
    riddor: incidents.filter(i => i.riddor_reportable || String(i.type) === 'riddor').length,
    closed: incidents.filter(i => ['closed','resolved'].includes(String(i.status ?? ''))).length,
    total: incidents.length,
  };

  const trendData = useMemo(() => buildTrendData(incidents), [incidents]);
  const riskHeatmap = useMemo(() => buildRiskHeatmap(incidents, rawProjects), [incidents, rawProjects]);
  const rootCauseData = useMemo(() => buildRootCauseData(incidents), [incidents]);
  const riskForecast = useMemo(() => buildRiskForecast(incidents), [incidents]);

  const overallSafetyScore = incidents.length ? Math.max(0, 100 - counts.open * 8 - counts.critical * 15) : 100;
  const safetyColor = overallSafetyScore >= 80 ? 'var(--emerald-400)' : overallSafetyScore >= 60 ? 'var(--amber-400)' : 'var(--red-400)';

  const selected = incidents.find(i => String(i.id) === selectedId);

  const openCreate = () => { setForm(defaultForm); setEditId(null); setShowModal(true); };
  const openEdit = (i: AnyRow) => {
    setForm({
      title: String(i.title ?? ''), type: String(i.type ?? 'near_miss'), severity: String(i.severity ?? 'medium'),
      status: String(i.status ?? 'open'), project: String(i.project ?? ''), location: String(i.location ?? ''),
      date: String(i.date ?? new Date().toISOString().split('T')[0]), description: String(i.description ?? ''),
      immediate_action: String(i.immediate_action ?? ''), injured_party: String(i.injured_party ?? ''),
      reported_by_name: String(i.reported_by_name ?? i.reportedBy ?? ''), riddor_reportable: Boolean(i.riddor_reportable),
      root_cause: String(i.root_cause ?? 'human_factor'),
    });
    setEditId(String(i.id)); setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editId) { await updateM.mutateAsync({ id: editId, data: form }); }
    else { await createM.mutateAsync(form); }
    setShowModal(false);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Delete this incident record?')) return;
    await deleteM.mutateAsync(id); setSelectedId(null);
  };

  const inp = "w-full bg-slate-800 border border-slate-600 rounded-lg px-4 py-2.5 text-white text-sm placeholder-slate-500 focus:outline-none focus:border-amber-500 transition-colors";
  const lbl = "block text-xs font-semibold text-slate-400 mb-1.5 uppercase tracking-wide";

  return (
    <div className="module-page" style={{ minHeight: '100%', background: 'var(--slate-950)', padding: '24px' }}>
      {/* ── HSE Intelligence Hub Header ─────────────────────────────────── */}
      <div className="card animate-fade-up" style={{ padding: '24px 28px', marginBottom: '20px', background: 'linear-gradient(135deg, rgba(13,17,23,0.95) 0%, rgba(8,11,18,0.9) 100%)', border: '1px solid var(--slate-700)', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none', opacity: 0.05, backgroundImage: `linear-gradient(rgba(248,113,113,0.3) 1px, transparent 1px), linear-gradient(90deg, rgba(248,113,113,0.3) 1px, transparent 1px)`, backgroundSize: '32px 32px' }} />
        <div style={{ display: 'grid', gridTemplateColumns: '1fr auto 1fr', alignItems: 'center', gap: '24px', position: 'relative', zIndex: 1 }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '6px' }}>
              <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', fontWeight: 800, color: 'var(--slate-50)', letterSpacing: '-0.03em', lineHeight: 1 }}>HSE Intelligence Hub</span>
              <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: overallSafetyScore >= 80 ? 'var(--emerald-400)' : overallSafetyScore >= 60 ? 'var(--amber-400)' : 'var(--red-400)', boxShadow: '0 0 8px currentColor', animation: 'pulse 2s ease-in-out infinite' }} />
            </div>
            <p style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', color: 'var(--slate-400)', letterSpacing: '0.06em' }}>HEALTH · SAFETY · ENVIRONMENT</p>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ display: 'inline-flex', alignItems: 'center', gap: '16px', padding: '12px 24px', background: 'rgba(248,113,113,0.08)', border: '1px solid rgba(248,113,113,0.2)', borderRadius: '12px' }}>
              <Shield style={{ width: '24px', height: '24px', color: safetyColor }} />
              <div>
                <div style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-400)', letterSpacing: '0.08em', textTransform: 'uppercase' }}>Safety Score</div>
                <div style={{ fontFamily: 'var(--font-display)', fontSize: '24px', fontWeight: 800, color: safetyColor, lineHeight: 1 }}>{overallSafetyScore}%</div>
              </div>
              {overallSafetyScore >= 80 ? <CheckCircle2 style={{ width: '20px', height: '20px', color: 'var(--emerald-400)' }} /> : <AlertTriangle style={{ width: '20px', height: '20px', color: 'var(--amber-400)' }} />}
            </div>
          </div>
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px' }}>
            <button onClick={() => refetch()} style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid var(--slate-700)', borderRadius: '8px', padding: '10px 16px', cursor: 'pointer', color: 'var(--slate-400)', transition: 'all 0.2s' }} onMouseEnter={e => { e.currentTarget.style.background = 'var(--slate-800)'; e.currentTarget.style.color = 'var(--slate-100)'; }}>
              <RefreshCw style={{ width: '16px', height: '16px' }} />
            </button>
