              <button onClick={() => setModule('projects')} style={{ background: 'rgba(245,158,11,0.1)', border: '1px solid rgba(245,158,11,0.3)', borderRadius: '6px', padding: '6px 12px', cursor: 'pointer', color: 'var(--amber-400)', fontFamily: 'var(--font-m

