  open:              { label: 'Open',             color: 'var(--red-400)',      bg: 'rgba(248,113,113,0.1)' },
  investigating:     { label: 'Investigating',    color: 'var(--amber-400)',    bg: 'rgba(245,158,11,0.1)' },
