  projects.forEach(p => { risk[String(p.name ?? 'Unknown')] = { name: String(p.name ?? 'Unknown'), critical: 0, high: 0, medium: 0, low: 0, score: 0 }; });
  incidents.forEach(inc => {
    const proj = String(inc.project ?? 'Unknown');
